var pallet = {};
var items = [];
var selectedAsset = null;
function fmt(d) {
  if (!d) return '—';
  return new Date(d).toLocaleDateString('en-GB', {
    day: '2-digit',
    month: 'short',
    year: 'numeric'
  });
}
function fmtUser(email) {
  if (!email) return '—';
  return email.split('@')[0];
}
function fmtCurrency(v) {
  if (!v && v !== 0) return '—';
  return '£' + Number(v).toFixed(2);
}
function statusBadge(s) {
  var cls = {
    open: 'badge-open',
    closed: 'badge-closed',
    shipped: 'badge-collected'
  };
  return 'badge ' + (cls[s] || 'badge-open');
}
function renderHeader(p) {
  if (!p) return;
  var ref = document.getElementById('hdr_pallet_ref');
  var st = document.getElementById('hdr_status');
  var cu = document.getElementById('meta_customer');
  var tv = document.getElementById('meta_total');
  var ic = document.getElementById('meta_item_count');
  var cr = document.getElementById('meta_created');
  if (ref) ref.textContent = p.pallet_ref || '—';
  if (st) {
    st.textContent = p.status || 'open';
    st.className = statusBadge(p.status);
  }
  if (cu) cu.textContent = p.customer_name || 'No customer assigned';
  if (tv) tv.textContent = fmtCurrency(p.total_value);
  if (ic) ic.textContent = (p.item_count || 0) + ' asset(s)';
  if (cr) cr.textContent = fmt(p.created_date);
}
function renderItems(its) {
  var tbody = document.getElementById('items_body');
  if (!tbody) return;
  if (!its || !its.length) {
    tbody.innerHTML = '<tr><td colspan="9" class="empty">No assets on this pallet yet</td></tr>';
    return;
  }
  tbody.innerHTML = its.map(function (it) {
    var ref = it.asset_ref ? '<span class="result-ref">' + it.asset_ref + '</span>' : '—';
    var desc = [it.make_name, it.model_name].filter(Boolean).join(' ') || '—';
    return '<tr>' + '<td>' + ref + '</td>' + '<td>' + (it.serial_number || '—') + '</td>' + '<td>' + desc + '</td>' + '<td>' + (it.cpu || '—') + '</td>' + '<td>' + (it.ram || '—') + '</td>' + '<td style="font-weight:700;color:#05042E">' + fmtCurrency(it.sale_price) + '</td>' + '<td>' + fmtUser(it.added_by) + '</td>' + '<td>' + fmt(it.added_date) + '</td>' + '<td><button class="btn-sm btn-danger" onclick="window.deleteItem(' + it.item_id + ')">Remove</button></td>' + '</tr>';
  }).join('');
}
function clearScan() {
  var el = document.getElementById('f_scan');
  if (el) el.value = '';
  var res = document.getElementById('asset_results');
  if (res) res.style.display = 'none';
  selectedAsset = null;
}
function render(model) {
  pallet = model.pallet || {};
  items = model.items || [];
  renderHeader(pallet);
  renderItems(items);
}
window.goBack = function () {
  appsmith.triggerEvent('onGoBack');
};
window.closePallet = function () {
  if (!confirm('Close this pallet without processing as a sale?')) return;
  appsmith.updateModel({
    close_pallet: true
  });
  appsmith.triggerEvent('onClosePallet');
};
window.searchAssets = function () {
  var q = document.getElementById('f_scan').value.trim();
  if (q.length < 2) {
    document.getElementById('asset_results').style.display = 'none';
    return;
  }
  appsmith.updateModel({
    search_query: q
  });
  appsmith.triggerEvent('onSearchAssets');
};
window.selectAsset = function (idx) {
  var results = appsmith.model.asset_results || [];
  selectedAsset = results[idx];
  if (!selectedAsset) return;
  appsmith.updateModel({
    item_asset_id: selectedAsset.asset_id,
    item_sale_price: 0,
    item_notes: ''
  });
  appsmith.triggerEvent('onSaveItem');
  clearScan();
};
window.deleteItem = function (itemId) {
  appsmith.updateModel({
    delete_item_id: itemId
  });
  appsmith.triggerEvent('onDeleteItem');
};
window.applyTotalPrice = function () {
  var total = parseFloat(document.getElementById('f_total_price').value);
  var count = (appsmith.model.items || []).length;
  if (!total || total <= 0) {
    alert('Enter a valid total price');
    return;
  }
  if (!count) {
    alert('Add assets to the pallet first');
    return;
  }
  var perAsset = (total / count).toFixed(2);
  document.getElementById('split_preview').textContent = count + ' asset(s) × £' + perAsset + ' each = £' + total.toFixed(2) + ' total';
  appsmith.updateModel({
    sale_total: total
  });
  appsmith.triggerEvent('onApplyPrice');
};
window.processOrder = function () {
  var count = (appsmith.model.items || []).length;
  if (!count) {
    alert('No assets on pallet — add assets before processing');
    return;
  }
  var total = appsmith.model.pallet && appsmith.model.pallet.total_value;
  if (!total || Number(total) <= 0) {
    alert('Apply a total price before processing the order');
    return;
  }
  if (!confirm('Process this pallet as a sale order?\n\n' + count + ' asset(s) will be marked as Sold and the pallet will be closed.')) return;
  appsmith.triggerEvent('onProcessOrder');
};
appsmith.onModelChange(function (model) {
  var ar = model.asset_results;
  if (ar !== undefined) {
    var el = document.getElementById('asset_results');
    if (ar && ar.length) {
      el.style.display = 'block';
      el.innerHTML = ar.map(function (r, i) {
        var desc = [r.make_name, r.model_name].filter(Boolean).join(' ');
        return '<div class="search-result-row" onclick="window.selectAsset(' + i + ')">' + '<div>' + '<span class="result-ref">' + r.asset_ref + '</span> ' + desc + '</div>' + '<div style="font-size:11px;color:#9ca3af;text-align:right;">' + (r.serial_number || '') + '<br>' + (r.status_name || '') + ' · ' + (r.location_name || '') + '</div>' + '</div>';
      }).join('');
    } else if (model.search_query) {
      el.style.display = 'block';
      el.innerHTML = '<div style="padding:10px 12px;font-size:12px;color:#888780;">No assets found for "' + model.search_query + '"</div>';
    } else {
      el.style.display = 'none';
    }
  }
  render(model);
});
appsmith.onReady(function () {
  render(appsmith.model);
});

