  if (!confirm('Process this pallet as a sale order?\n\n' + count + ' asset(s) will be marked as Sold and the pallet will be closed.')) return;
  appsmith.triggerEvent('onProcessOrder');
};

appsmith.onModelChange(function(model) {
  var ar = model.asset_results;
  if (ar !== undefined) {
    var el = document.getElementById('asset_results');
    if (ar && ar.length) {
      el.style.display = 'block';
      el.innerHTML = ar.map(function(r,i) {
        var desc = [r.make_name, r.model_name].filter(Boolean).join(' ');
        return '<div class="search-result-row" onclick="window.selectAsset('+i+')">'+
          '<div>'+
          '<span class="result-ref">'+r.asset_ref+'</span> '+desc+
          '</div>'+
          '<div style="font-size:11px;color:#9ca3af;text-align:right;">'+
          (r.serial_number||'')+
          '<br>'+(r.status_name||'')+' · '+(r.location_name||'')+'</div>'+
          '</div>';
      }).join('');
    } else if (model.search_query) {
      el.style.display = 'block';
      el.innerHTML = '<div style="padding:10px 12px;font-size:12px;color:#888780;">No assets found for "'+model.search_query+'"</div>';
    } else {
      el.style.display = 'none';
    }
  }
  render(model);
});

appsmith.onReady(function() { render(appsmith.model); });
